SELECT 
FROM bluenote_feed.feed_inbox_item
WHERE user_id = #{userId}
  AND item_status = 'VISIBLE'

  AND (
    published_at < #{cursorPublishedAt}
    OR (published_at = #{cursorPublishedAt} AND note_id < #{cursorNoteId})
  )

ORDER BY published_at DESC, note_id DESC
LIMIT #{size}

SELECT 
FROM bluenote_feed.feed_inbox_item
WHERE user_id = #{userId}
  AND item_status = 'VISIBLE'
  AND note_id IN

    #{noteId}

SELECT 
FROM bluenote_feed.feed_inbox_item
WHERE user_id = #{userId}
  AND item_status = 'VISIBLE'
ORDER BY published_at DESC, note_id DESC
LIMIT #{size}

