UPDATE bluenote_feed.feed_inbox_item
SET item_status = 'HIDDEN',
    updated_at = #{updatedAt}
WHERE user_id = #{userId}
  AND author_id = #{authorId}
  AND item_status = 'VISIBLE'

UPDATE bluenote_feed.feed_inbox_item
SET item_status = #{itemStatus},
    updated_at = #{updatedAt}
WHERE note_id = #{noteId}
